public static long[] solve(long c, long[][] connections, long[][] queries) {
    // Initialize parent and min arrays for Union-Find
    long[] parent = new long[(int) c + 1];
    long[] min = new long[(int) c + 1];
    for (long i = 1; i <= c; i++) {
        parent[(int) i] = i;
        min[(int) i] = i;
    }

    // Union all connections
    for (long[] conn : connections) {
        long u = conn[0];
        long v = conn[1];
        union(parent, min, u, v);
    }

    // Track online status
    boolean[] online = new boolean[(int) c + 1];
    Arrays.fill(online, true);

    // Process queries
    List<Long> result = new ArrayList<>();
    for (long[] query : queries) {
        long type = query[0];
        long x = query[1];
        if (type == 1) {
            if (online[(int) x]) {
                result.add(x);
            } else {
                long root = find(parent, x);
                long currentMin = min[(int) root];
                // Find the smallest online node in the component
                long res = -1;
                while (currentMin <= c) {
                    if (online[(int) currentMin] && find(parent, currentMin) == root) {
                        res = currentMin;
                        break;
                    }
                    currentMin++;
                }
                result.add(res);
            }
        } else if (type == 2) {
            online[(int) x] = false;
        }
    }

    // Convert result to long[]
    long[] resArray = new long[result.size()];
    for (int i = 0; i < result.size(); i++) {
        resArray[i] = result.get(i);
    }
    return resArray;
}

private static long find(long[] parent, long x) {
    if (parent[(int) x] != x) {
        parent[(int) x] = find(parent, parent[(int) x]);
    }
    return parent[(int) x];
}

private static void union(long[] parent, long[] min, long u, long v) {
    long rootU = find(parent, u);
    long rootV = find(parent, v);
    if (rootU != rootV) {
        if (rootU < rootV) {
            parent[(int) rootV] = rootU;
            min[(int) rootU] = Math.min(min[(int) rootU], min[(int) rootV]);
        } else {
            parent[(int) rootU] = rootV;
            min[(int) rootV] = Math.min(min[(int) rootU], min[(int) rootV]);
        }
    }
}
