public static long[] solve(long c, long[][] connections, long[][] queries) {
    // Initialize parent and min arrays for Union-Find
    long[] parent = new long[(int) (c + 1)];
    long[] min = new long[(int) (c + 1)];
    for (long i = 1; i <= c; i++) {
        parent[(int) i] = i;
        min[(int) i] = i;
    }

    // Union all connected components
    for (long[] conn : connections) {
        long u = conn[0];
        long v = conn[1];
        union(parent, min, u, v);
    }

    // Track online status
    boolean[] online = new boolean[(int) (c + 1)];
    Arrays.fill(online, true);

    // Process queries
    List<Long> result = new ArrayList<>();
    for (long[] query : queries) {
        long type = query[0];
        long x = query[1];
        if (type == 1) {
            if (online[(int) x]) {
                result.add(x);
            } else {
                long root = find(parent, x);
                long currentMin = min[(int) root];
                // Find the minimal online node in the component
                long answer = -1;
                while (currentMin <= c) {
                    if (online[(int) currentMin] && find(parent, currentMin) == root) {
                        answer = currentMin;
                        break;
                    }
                    currentMin++;
                }
                result.add(answer);
            }
        } else if (type == 2) {
            online[(int) x] = false;
        }
    }

    // Convert result to long array
    long[] res = new long[result.size()];
    for (int i = 0; i < res.length; i++) {
        res[i] = result.get(i);
    }
    return res;
