static class UnionFind {
    private int[] parent;
    private int[] rank;
    private Map<Integer, TreeSet<Integer>> rootToNodes;

    public UnionFind(int size) {
        parent = new int[size + 1];
        rank = new int[size + 1];
        rootToNodes = new HashMap<>();
        for (int i = 1; i <= size; i++) {
            parent[i] = i;
            rank[i] = 1;
            TreeSet<Integer> set = new TreeSet<>();
            set.add(i);
            rootToNodes.put(i, set);
        }
    }

    public int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    public void union(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX == rootY) {
            return;
        }
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
            rootToNodes.get(rootX).addAll(rootToNodes.get(rootY));
            rootToNodes.remove(rootY);
        } else if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
            rootToNodes.get(rootY).addAll(rootToNodes.get(rootX));
            rootToNodes.remove(rootX);
        } else {
            parent[rootY] = rootX;
            rootToNodes.get(rootX).addAll(rootToNodes.get(rootY));
            rootToNodes.remove(rootY);
            rank[rootX]++;
        }
    }

    public long getMinOnlineId(int root, boolean[] online) {
        TreeSet<Integer> nodes = rootToNodes.get(root);
        if (nodes == null) {
            return -1;
        }
        for (int node : nodes) {
            if (online[node]) {
                return node;
            }
        }
        return -1;
    }
}
