    int[] parent = new int[n + 1];
    boolean[] online = new boolean[n + 1];
    Arrays.fill(online, true);

    // Initialize parent as self
    for (int i = 1; i <= n; i++) {
        parent[i] = i;
    }

    // Union all connections
    for (long[] conn : connections) {
        int u = (int) conn[0];
        int v = (int) conn[1];
        union(parent, u, v);
    }

    // For each component, track the min online node
    Map<Integer, TreeSet<Integer>> componentMin = new HashMap<>();
    for (int i = 1; i <= n; i++) {
        int root = find(parent, i);
        componentMin.putIfAbsent(root, new TreeSet<>());
        componentMin.get(root).add(i);
    }

    List<Long> result = new ArrayList<>();

    for (long[] query : queries) {
        int type = (int) query[0];
        int x = (int) query[1];

        if (type == 1) {
            int root = find(parent, x);
            TreeSet<Integer> set = componentMin.get(root);
            if (set.isEmpty()) {
                result.add(-1L);
            } else {
                if (online[x]) {
                    result.add((long) x);
                } else {
                    result.add((long) set.first());
                }
            }
        } else if (type == 2) {
            if (online[x]) {
                online[x] = false;
                int root = find(parent, x);
                TreeSet<Integer> set = componentMin.get(root);
                set.remove(x);
            }
        }
    }

    long[] res = new long[result.size()];
    for (int i = 0; i < res.length; i++) {
        res[i] = result.get(i);
    }
    return res;
}

private static int find(int[] parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

private static void union(int[] parent, int x, int y) {
    int rootX = find(parent, x);
    int rootY = find(parent, y);
    if (rootX != rootY) {
        parent[rootY] = rootX;
    }
